mapper.select:
SELECT a.iboard boardId, a.title, d.NAME subjectName, c.unm nm, a.created_at createdAt FROM board a INNER JOIN board_category b ON a.icategory = b.icategory INNER JOIN user c ON a.iuser = c.iuser INNER JOIN board_subject d ON a.isubject = d.isubject WHERE b.icategory = #{categoryId}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.contents LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.iboard DESC LIMIT #{pageStart}, #{amount}

mapper.update:
UPDATE board SET
title = #{title},
isubject = ${subjectId},
contents = #{contents}
WHERE iboard = #{boardId}
